const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const itemPremium = (item: Item): number => {
  const base = basePremiumFor(item);
  return base + base * FIRST_INSURANCE_RATE;
};

const quotePremium = (items: Item[]): number => {
  const itemsTotal = items.reduce((total, item) => total + itemPremium(item), 0);
  return Math.ceil(itemsTotal + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
});

