import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---------- Simple quote: empty + single items ----------
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single plain sword (newcomer, first contract) → premium = 100 base + 10 first insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single plain amulet (newcomer, first contract) → premium = 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single plain staff (newcomer, first contract) → premium = 80 + 8 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single plain potion (newcomer, first contract) → premium = 40 + 4 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ---------- Components and block-of-3 ----------
  it("2 runes → 50 G base premium (no block); total 50 + 5 surcharge + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block applies); total 60 + 6 surcharge + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base premium (no block — block requires exactly 3); total 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base premium; total 175 + 17.5 + 5 = 197.5 → ceil 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone → 75 G base; total 75 + 7.5 + 5 = 87.5 → ceil 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base (two blocks); total 120 + 12 + 5 = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ---------- Item-level modifiers ----------
  it("cursed sword (newcomer, first contract, ench 3) → 100 + 50 curse + 10 first insurance + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with exactly enchantment 5 → high-enchantment surcharge applies; 100 + 30 + 10 + 5 = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge; total 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword with enchantment 5 → both surcharges; 100 + 50 + 30 + 10 + 5 = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // ---------- Policy-wide modifiers ----------
  it("customer with exactly 2 years → loyalty 20% discount; plain sword: 100 + 10 - 20 + 5 = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("customer with 1 year → no loyalty; plain sword: 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 1 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("two quotes in scenario → second gets follow-up discount: 115, then 100 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "quote", items: [{ type: "sword" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
  });

  // ---------- Modifier scope on multi-item policies ----------
  it("cursed sword + plain amulet → curse only on sword; 160 + 50 + 16 + 5 = 231 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", cursed: true }, { type: "amulet" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });
  it.todo("first insurance surcharge applies per item, not per policy");

  // ---------- Rounding in MHPCO's favor ----------
  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");
  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");

  // ---------- Integration premium examples ----------
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo("long-standing (3y) customer's second contract: cursed sword enchantment 7 → premium 160 G");

  // ---------- Claims: simple cases ----------
  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 G (full minus deductible)");
  it.todo("damage to a rune (insurance value 250), damage 200 → payout 100 G (full minus deductible)");

  // ---------- Claims: special clauses ----------
  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (dragon: full, minus deductible)");
  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (high-enchantment then deductible)");

  // ---------- Claims: deductible per damage event ----------
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applies per item)");

  // ---------- Claims: cap ----------
  it.todo("cursed sword (insurance value 1000) → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block does not affect insurance sum)");
  it.todo("sword cap 2000 G, two successive claims of 1500: first payout 1400, cap remaining 600; second payout 600, cap remaining 0");

  // ---------- Claims: multiple items of same type ----------
  it.todo("policy of two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two swords insured, two sword damage entries → each treated as separate damage with own deductible");
  it.todo("damages has more entries of a type than insured → CLI exits non-zero");

  // ---------- Edge cases / errors ----------
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results on stdout");
  it.todo("claim references damage entry whose item is not part of policy → CLI exits non-zero");
  it.todo("claim with damage entry of unknown item type → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");

  // ---------- CLI / multi-step scenario ----------
  it.todo("scenario with quote then claim returns results array of matching length and order");
  it.todo("claim's policy field references quote step by zero-based index");
});

